import React, { useState, useEffect } from 'react';
import AuthPage from './components/AuthPage';
import Dashboard from './components/Dashboard';
import AdminDashboard from './components/AdminDashboard';
import HRDashboard from './components/HRDashboard';
import { Student, Admin, HumanResource } from './types';
import { supabase } from './lib/supabaseClient';

function App() {
  const [studentProfile, setStudentProfile] = useState<Student | null>(null);
  const [adminProfile, setAdminProfile] = useState<Admin | null>(null);
  const [hrProfile, setHrProfile] = useState<HumanResource | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Check for persisted sessions in localStorage
    const storedUser = localStorage.getItem('lu_tracer_user');
    const storedAdmin = localStorage.getItem('lu_tracer_admin');
    const storedHR = localStorage.getItem('lu_tracer_hr');

    if (storedAdmin) {
      try {
        const parsedAdmin = JSON.parse(storedAdmin);
        setAdminProfile(parsedAdmin);
      } catch (e) {
        console.error("Failed to parse stored admin", e);
        localStorage.removeItem('lu_tracer_admin');
      }
    } else if (storedHR) {
      try {
        const parsedHR = JSON.parse(storedHR);
        setHrProfile(parsedHR);
      } catch (e) {
        console.error("Failed to parse stored HR", e);
        localStorage.removeItem('lu_tracer_hr');
      }
    } else if (storedUser) {
      try {
        const parsedUser = JSON.parse(storedUser);
        setStudentProfile(parsedUser);
      } catch (e) {
        console.error("Failed to parse stored user", e);
        localStorage.removeItem('lu_tracer_user');
      }
    }
    setLoading(false);
  }, []);

  const handleLoginSuccess = (student: Student) => {
    setStudentProfile(student);
    localStorage.setItem('lu_tracer_user', JSON.stringify(student));
    // Ensure others are logged out
    setAdminProfile(null);
    setHrProfile(null);
    localStorage.removeItem('lu_tracer_admin');
    localStorage.removeItem('lu_tracer_hr');
  };

  const handleAdminLoginSuccess = (admin: Admin) => {
    setAdminProfile(admin);
    localStorage.setItem('lu_tracer_admin', JSON.stringify(admin));
    // Ensure others are logged out
    setStudentProfile(null);
    setHrProfile(null);
    localStorage.removeItem('lu_tracer_user');
    localStorage.removeItem('lu_tracer_hr');
  };

  const handleHRLoginSuccess = (hr: HumanResource) => {
    setHrProfile(hr);
    localStorage.setItem('lu_tracer_hr', JSON.stringify(hr));
    // Ensure others are logged out
    setStudentProfile(null);
    setAdminProfile(null);
    localStorage.removeItem('lu_tracer_user');
    localStorage.removeItem('lu_tracer_admin');
  };

  const handleLogout = async () => {
    // Clear all sessions
    localStorage.removeItem('lu_tracer_user');
    localStorage.removeItem('lu_tracer_admin');
    localStorage.removeItem('lu_tracer_hr');
    setStudentProfile(null);
    setAdminProfile(null);
    setHrProfile(null);
    // Optional: Sign out from supabase
    await supabase.auth.signOut();
  };

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-green-50">
        <div className="w-16 h-16 border-4 border-green-600 border-t-transparent rounded-full animate-spin"></div>
      </div>
    );
  }

  // Admin Dashboard
  if (adminProfile) {
    return <AdminDashboard onLogout={handleLogout} />;
  }

  // HR Dashboard
  if (hrProfile) {
    return <HRDashboard hr={hrProfile} onLogout={handleLogout} />;
  }

  // Student/Alumni Dashboard
  if (studentProfile) {
    return <Dashboard user={studentProfile} onLogout={handleLogout} />;
  }

  // Login/Signup Page
  return (
    <AuthPage 
      onLoginSuccess={handleLoginSuccess}
      onAdminLoginSuccess={handleAdminLoginSuccess}
      onHRLoginSuccess={handleHRLoginSuccess}
    />
  );
}

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { HumanResource, JobPosting, JobApplication, JobMessage, Student } from '../types';
import { LogOut, Briefcase, Users, MessageSquare, Plus, Search, MapPin, DollarSign, Calendar, Trash2, Edit, X, Save, Send, Loader2, CheckCircle, FileText, ArrowRight, Clock, Award, Filter, ExternalLink } from 'lucide-react';
import { getHRJobs, createJob, updateJob, deleteJob, getHRApplications, updateApplicationStatus, getMessages, sendMessage, getResumeBlob } from '../services/jobService';
import { sendHiredEmail } from '../services/emailService';

interface HRDashboardProps {
  hr: HumanResource;
  onLogout: () => void;
}

const HRDashboard: React.FC<HRDashboardProps> = ({ hr, onLogout }) => {
  const [activeTab, setActiveTab] = useState<'jobs' | 'applications'>('jobs');

  // Jobs State
  const [jobs, setJobs] = useState<JobPosting[]>([]);
  const [loadingJobs, setLoadingJobs] = useState(false);
  const [isJobModalOpen, setIsJobModalOpen] = useState(false);
  const [editingJob, setEditingJob] = useState<JobPosting | null>(null);
  const [jobFormData, setJobFormData] = useState<Partial<JobPosting>>({});

  // Applications/Chat State
  const [applications, setApplications] = useState<JobApplication[]>([]);
  const [selectedApplication, setSelectedApplication] = useState<JobApplication | null>(null);
  const [messages, setMessages] = useState<JobMessage[]>([]);
  const [newMessage, setNewMessage] = useState('');
  const [loadingApps, setLoadingApps] = useState(false);
  const [loadingMessages, setLoadingMessages] = useState(false);
  const [sending, setSending] = useState(false);

  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Initial Data Load
  useEffect(() => {
    fetchJobs();
    fetchApplications();
  }, [hr.id]);

  useEffect(() => {
    if (activeTab === 'applications') {
        fetchApplications();
    } else {
        fetchJobs();
    }
  }, [activeTab]);

  useEffect(() => {
    if (selectedApplication) {
        fetchMessages(selectedApplication.id);
        // Set up interval for polling messages
        const interval = setInterval(() => {
            fetchMessages(selectedApplication.id);
        }, 5000);
        return () => clearInterval(interval);
    }
  }, [selectedApplication]);

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  // --- JOB ACTIONS ---

  const fetchJobs = async () => {
    setLoadingJobs(true);
    try {
        const data = await getHRJobs(hr.id);
        setJobs(data);
    } catch (e) {
        console.error(e);
    } finally {
        setLoadingJobs(false);
    }
  };

  const handleCreateJob = () => {
    setEditingJob(null);
    setJobFormData({
        hr_id: hr.id,
        company_name: hr.company_name,
        employment_type: 'Full-Time',
        is_active: true
    });
    setIsJobModalOpen(true);
  };

  const handleEditJob = (job: JobPosting) => {
      setEditingJob(job);
      setJobFormData(job);
      setIsJobModalOpen(true);
  };

  const handleDeleteJob = async (id: string) => {
      if(!window.confirm("Are you sure you want to delete this job posting?")) return;
      try {
          await deleteJob(id);
          fetchJobs();
      } catch (e) {
          alert("Failed to delete job.");
      }
  };

  const saveJob = async (e: React.FormEvent) => {
      e.preventDefault();
      try {
          if (editingJob) {
              await updateJob(editingJob.id, jobFormData);
          } else {
              await createJob(jobFormData);
          }
          setIsJobModalOpen(false);
          fetchJobs();
      } catch (e) {
          console.error(e);
          alert("Failed to save job.");
      }
  };

  // --- APPLICATION ACTIONS ---

  const fetchApplications = async () => {
      setLoadingApps(true);
      try {
          const data = await getHRApplications(hr.id);
          setApplications(data);
      } catch (e) {
          console.error(e);
      } finally {
          setLoadingApps(false);
      }
  };

  const fetchMessages = async (appId: string) => {
      try {
          const data = await getMessages(appId);
          setMessages(data);
      } catch (e) { console.error(e); }
  };

  const handleSendMessage = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!newMessage.trim() || !selectedApplication) return;
      setSending(true);
      try {
          await sendMessage({
              application_id: selectedApplication.id,
              sender_type: 'HR',
              hr_id: hr.id,
              message: newMessage,
              is_read: false
          });
          setNewMessage('');
          fetchMessages(selectedApplication.id);
      } catch (e) {
          alert("Failed to send.");
      } finally {
          setSending(false);
      }
  };

  const changeStatus = async (status: string) => {
      if (!selectedApplication) return;
      if (status === 'Hired') {
          if (!window.confirm("Are you sure you want to hire this applicant? This will trigger an email notification.")) return;
      }

      try {
          // @ts-ignore
          await updateApplicationStatus(selectedApplication.id, status);

          if (status === 'Hired' && selectedApplication.applicant_details && selectedApplication.job) {
             await sendHiredEmail(
                 `${selectedApplication.applicant_details.first_name} ${selectedApplication.applicant_details.last_name}`,
                 selectedApplication.applicant_details.email,
                 selectedApplication.job.job_title,
                 hr.company_name
             );
             alert("Applicant hired! Notification email sent.");
          }

          // Update local state
          setSelectedApplication(prev => prev ? ({ ...prev, application_status: status as any }) : null);
          fetchApplications();
      } catch (e) {
          alert("Failed to update status.");
      }
  };

  // Helper to open resume
  const openResume = (hexString?: string) => {
      if (!hexString) {
          alert("No resume uploaded for this applicant.");
          return;
      }
      const url = getResumeBlob(hexString);
      if (url) window.open(url, '_blank');
      else alert("Invalid resume format.");
  };

  // --- RENDER ---

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col font-sans">

      {/* Top Navbar */}
      <header className="bg-white border-b border-gray-200 sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 h-16 flex justify-between items-center">
             <div className="flex items-center gap-3">
                 <div className="w-10 h-10 bg-blue-600 rounded-lg flex items-center justify-center text-white shadow-md">
                     <Briefcase size={20} />
                 </div>
                 <div>
                     <h1 className="font-bold text-gray-800 text-lg leading-tight">{hr.company_name}</h1>
                     <p className="text-xs text-gray-500 font-medium">HR Portal</p>
                 </div>
             </div>
             <button onClick={onLogout} className="text-gray-400 hover:text-red-500 transition-colors p-2">
                 <LogOut size={20} />
             </button>
        </div>
      </header>

      {/* Main Container */}
      <main className="flex-grow max-w-7xl mx-auto w-full px-4 py-8 flex flex-col h-[calc(100vh-64px)]">

          {/* Tabs */}
          <div className="flex gap-6 border-b border-gray-200 mb-6 flex-shrink-0">
