// --- RESUME HELPER ---
export const getResumeBlob = (hexString: string): string | null => {
    if (!hexString || !hexString.startsWith('\\x')) return null;

    // Convert hex string (Postgres bytea format \x...) to byte array
    const hex = hexString.substring(2);
    const bytes = new Uint8Array(hex.length / 2);
    for (let i = 0; i < hex.length; i += 2) {
      bytes[i / 2] = parseInt(hex.substring(i, i + 2), 16);
    }

    const blob = new Blob([bytes], { type: 'application/pdf' });
    return URL.createObjectURL(blob);
};

import React, { useState, useEffect, useRef } from 'react';
import { JobApplication, JobMessage, Student } from '../types';
import { getMessages, sendMessage } from '../services/jobService';
import { Send, X, MessageSquare, Briefcase, User } from 'lucide-react';

interface JobChatModalProps {
  application: JobApplication;
  user: Student; // Current logged in user
  onClose: () => void;
}

const JobChatModal: React.FC<JobChatModalProps> = ({ application, user, onClose }) => {
  const [messages, setMessages] = useState<JobMessage[]>([]);
  const [newMessage, setNewMessage] = useState('');
  const [sending, setSending] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    fetchMessages();
    const interval = setInterval(fetchMessages, 3000); // Poll every 3s
    return () => clearInterval(interval);
  }, [application.id]);

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const fetchMessages = async () => {
    try {
        const data = await getMessages(application.id);
        setMessages(data);
    } catch (e) { console.error(e); }
  };

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  const handleSend = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!newMessage.trim()) return;

      setSending(true);
      try {
          const userType = user.table_source === 'students' ? 'STUDENT' : 'ALUMNI';
          const payload: Partial<JobMessage> = {
              application_id: application.id,
              sender_type: userType,
              message: newMessage,
              is_read: false
          };

          if (userType === 'STUDENT') payload.student_id = user.id;
          else payload.alumni_id = user.id;

          await sendMessage(payload);
          setNewMessage('');
          fetchMessages();
      } catch (e) {
          alert("Failed to send message");
      } finally {
          setSending(false);
      }
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
        <div className="absolute inset-0 bg-gray-900/50 backdrop-blur-sm" onClick={onClose}></div>
        <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md h-[600px] flex flex-col relative z-10 overflow-hidden animate-in zoom-in-95 duration-200">

            {/* Header */}
            <div className="p-4 border-b border-gray-100 bg-gradient-to-r from-blue-600 to-blue-700 text-white flex justify-between items-center">
                <div className="flex items-center gap-3">
                    <div className="p-2 bg-white/20 rounded-lg backdrop-blur-sm">
                        <Briefcase size={20} />
                    </div>
                    <div>
                        <h3 className="font-bold text-sm leading-tight">{application.job?.company_name}</h3>
                        <p className="text-xs opacity-80">{application.job?.job_title}</p>
                    </div>
                </div>
                <button onClick={onClose} className="p-2 hover:bg-white/20 rounded-full transition-colors"><X size={20}/></button>
            </div>

            {/* Chat Body */}
            <div className="flex-grow p-4 overflow-y-auto bg-gray-50 space-y-3">
                {messages.length === 0 ? (
                    <div className="flex flex-col items-center justify-center h-full text-gray-400">
                        <MessageSquare size={48} className="mb-2 opacity-20"/>
                        <p className="text-sm font-medium">Start a conversation with HR</p>
                    </div>
                ) : (
                    messages.map((msg) => {
                        const isMe = msg.sender_type !== 'HR';
                        return (
                            <div key={msg.id} className={`flex ${isMe ? 'justify-end' : 'justify-start'}`}>
                                <div className={`flex items-end gap-2 max-w-[80%] ${isMe ? 'flex-row-reverse' : 'flex-row'}`}>
                                    <div className={`w-6 h-6 rounded-full flex items-center justify-center text-[10px] font-bold shrink-0 ${isMe ? 'bg-blue-200 text-blue-700' : 'bg-gray-200 text-gray-600'}`}>
                                        {isMe ? 'ME' : 'HR'}
                                    </div>
                                    <div className={`px-4 py-2 rounded-2xl text-sm shadow-sm ${
                                        isMe 
                                        ? 'bg-blue-600 text-white rounded-br-none' 
                                        : 'bg-white text-gray-800 border border-gray-100 rounded-bl-none'
                                    }`}>
                                        {msg.message}
                                    </div>
                                </div>
                            </div>
                        );
                    })
                )}
                <div ref={messagesEndRef} />
            </div>

            {/* Input */}
            <form onSubmit={handleSend} className="p-3 bg-white border-t border-gray-100 flex gap-2">
                <input 
                    type="text" 
                    value={newMessage}
                    onChange={(e) => setNewMessage(e.target.value)}
                    placeholder="Type your message..."
                    className="flex-grow bg-gray-100 rounded-full px-4 py-2.5 text-sm outline-none focus:ring-2 focus:ring-blue-100 transition-all"
                />
                <button 
                    type="submit" 
                    disabled={!newMessage.trim() || sending}
                    className="bg-blue-600 hover:bg-blue-700 text-white p-2.5 rounded-full transition-all disabled:opacity-50 disabled:scale-95 shadow-md"
                >
                    <Send size={18} />
                </button>
            </form>
        </div>
    </div>
  );
};

