  const [selectedChatApp, setSelectedChatApp] = useState<JobApplication | null>(null);

  useEffect(() => {
    if (activeTab === 'browse') {
        fetchJobs();
    } else {
        fetchApplications();
    }
  }, [activeTab]);

  const fetchJobs = async () => {
      setLoading(true);
      try {
          const allJobs = await getOpenJobs();
          // We also need to know which ones we've already applied to, to update UI
          const userApps = await getUserApplications(user.id!, user.table_source === 'students' ? 'student' : 'alumni');
          const appliedJobIds = new Set(userApps.map(app => app.job_posting_id));

          // Add a flag to jobs locally (not in type, but useful for UI)
          const jobsWithStatus = allJobs.map(job => ({
              ...job,
              hasApplied: appliedJobIds.has(job.id)
          }));

          // @ts-ignore
          setJobs(jobsWithStatus);
      } catch (e) {
          console.error(e);
      } finally {
          setLoading(false);
      }
  };

  const fetchApplications = async () => {
      setLoading(true);
      try {
          const userType = user.table_source === 'students' ? 'student' : 'alumni';
