  };

  const handleApply = async (jobId: string) => {
      if (!window.confirm("Are you sure you want to apply for this position? Your profile will be shared with the HR.")) return;

      setApplyingId(jobId);
      try {
          const userType = user.table_source === 'students' ? 'student' : 'alumni';
          await applyForJob(jobId, user.id!, userType);

