import React, { useState, useEffect } from 'react';
import { JobPosting, Student } from '../types';
import { getOpenJobs, applyForJob, getUserApplications } from '../services/jobService';
import { Sparkles, Briefcase, MapPin, Loader2, CheckCircle, ToggleRight, ToggleLeft } from 'lucide-react';

interface ForYouPageProps {
  user: Student;
}

const ForYouPage: React.FC<ForYouPageProps> = ({ user }) => {
  const [loading, setLoading] = useState(true);
  const [matchedJobs, setMatchedJobs] = useState<JobPosting[]>([]);
  const [showAllToggle, setShowAllToggle] = useState(false);
  const [allJobsCache, setAllJobsCache] = useState<JobPosting[]>([]); // Cache for toggling
  const [applyingId, setApplyingId] = useState<string | null>(null);
  const [appliedIds, setAppliedIds] = useState<Set<string>>(new Set());

  useEffect(() => {
    fetchAndMatchJobs();
  }, []);

  const fetchAndMatchJobs = async () => {
    setLoading(true);
    try {
        const [jobs, userApps] = await Promise.all([
            getOpenJobs(),
            getUserApplications(user.id!, user.table_source === 'students' ? 'student' : 'alumni')
        ]);

        const appSet = new Set(userApps.map(a => a.job_posting_id));
        setAppliedIds(appSet);
        setAllJobsCache(jobs);

        // --- MATCHING LOGIC ---
        const matches = jobs.filter(job => {
            let score = 0;
            const program = user.program.toLowerCase();
            const jobTitle = job.job_title.toLowerCase();
            const jobDesc = job.job_description.toLowerCase();
            const industry = job.industry.toLowerCase();

            // 1. Program Keyword Match (High Weight)
            // Extract core words from program (e.g., "Information Technology" -> "technology", "information")
            const progKeywords = program.replace('bachelor of science in', '').replace('bachelor of', '').split(' ');
            const hasProgMatch = progKeywords.some(k => k.length > 3 && (jobTitle.includes(k) || jobDesc.includes(k)));

            if (hasProgMatch) score += 30;

            // 2. Exact Program Match (Very High Weight)
            if (program.includes('information technology') || program.includes('computer science')) {
                if (jobTitle.includes('developer') || jobTitle.includes('engineer') || jobTitle.includes('it') || industry.includes('tech')) score += 20;
            }
            if (program.includes('accountancy') || program.includes('accounting')) {
                if (jobTitle.includes('accountant') || jobTitle.includes('audit') || jobTitle.includes('finance')) score += 20;
            }
            if (program.includes('education')) {
                if (jobTitle.includes('teacher') || jobTitle.includes('tutor') || industry.includes('education')) score += 20;
            }

            // 3. Job Level (Fresh Grad Priority)
            if (user.year_level && parseInt(user.year_level) >= new Date().getFullYear()) {
                // User is graduating or fresh
                if (job.job_level.toLowerCase().includes('entry') || job.job_level.toLowerCase().includes('fresh') || job.job_level.toLowerCase().includes('associate')) {
                    score += 15;
                }
            }

            return score >= 15; // Threshold for "For You"
        });

        setMatchedJobs(matches);

    } catch (e) {
        console.error(e);
    } finally {
        setLoading(false);
    }
  };

  const handleApply = async (jobId: string) => {
      if (!window.confirm("Apply to this recommended job?")) return;
      setApplyingId(jobId);
      try {
          const userType = user.table_source === 'students' ? 'student' : 'alumni';
          await applyForJob(jobId, user.id!, userType);
          setAppliedIds(prev => new Set(prev).add(jobId));
          alert("Applied successfully!");
      } catch (e) {
          console.error(e);
          alert("Error applying.");
      } finally {
          setApplyingId(null);
      }
  };

  const displayedJobs = showAllToggle ? allJobsCache : matchedJobs;

  return (
    <div className="space-y-6 animate-fade-in pb-10">

        {/* Header Area */}
        <div className="flex flex-col md:flex-row justify-between items-end gap-4 border-b border-gray-200 pb-4">
            <div>
                <div className="flex items-center gap-2 mb-1">
                    <Sparkles className="text-luGold-dark" size={20} />
                    <h2 className="text-xl font-bold text-gray-800">Jobs For You</h2>
                </div>
                <p className="text-sm text-gray-500">Curated based on your program <span className="font-bold text-gray-700">({user.program})</span> and profile.</p>
            </div>

            {/* Toggle */}
            <button 
                onClick={() => setShowAllToggle(!showAllToggle)}
                className="flex items-center gap-2 text-sm font-bold text-gray-600 hover:text-gray-900 transition-colors"
            >
                {showAllToggle ? <ToggleRight className="text-blue-600" size={32} /> : <ToggleLeft className="text-gray-400" size={32} />}
                Show All Jobs
            </button>
        </div>

        {loading ? (
            <div className="flex justify-center py-20"><Loader2 className="animate-spin text-gray-300 w-8 h-8"/></div>
        ) : displayedJobs.length === 0 ? (
            <div className="text-center py-20 bg-white rounded-3xl border border-dashed border-gray-200">
                <Sparkles className="w-12 h-12 text-gray-300 mx-auto mb-4" />
                <p className="text-gray-500 font-bold">No recommendations found yet.</p>
                <button onClick={() => setShowAllToggle(true)} className="mt-2 text-blue-600 text-sm font-bold hover:underline">View all jobs instead</button>
            </div>
        ) : (
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                {displayedJobs.map(job => (
                    <div key={job.id} className={`bg-white p-6 rounded-3xl border transition-all duration-300 relative group flex flex-col ${!showAllToggle ? 'border-luGold/30 shadow-lg shadow-yellow-500/5' : 'border-gray-100 shadow-sm hover:shadow-md'}`}>

                        {!showAllToggle && (
                            <div className="absolute top-4 right-4 text-[10px] font-bold uppercase tracking-wider text-luGold-dark bg-yellow-50 px-2 py-1 rounded-lg border border-yellow-100">
                                Recommended
                            </div>
                        )}

                        <div className="mb-4">
                            <h3 className="text-lg font-bold text-gray-900 group-hover:text-blue-600 transition-colors">{job.job_title}</h3>
                            <p className="text-sm font-semibold text-gray-500">{job.company_name}</p>
                        </div>

                        <div className="flex flex-wrap gap-2 mb-4 text-xs font-bold text-gray-600">
                            <span className="bg-gray-50 px-2 py-1 rounded border border-gray-100 flex items-center gap-1"><MapPin size={10}/> {job.location}</span>
                            <span className="bg-gray-50 px-2 py-1 rounded border border-gray-100">{job.employment_type}</span>
                            <span className="bg-gray-50 px-2 py-1 rounded border border-gray-100">{job.salary_range}</span>
                        </div>

                        <p className="text-sm text-gray-600 line-clamp-2 mb-6 flex-grow">{job.job_description}</p>

                        <button 
                            onClick={() => handleApply(job.id)}
                            disabled={appliedIds.has(job.id) || applyingId === job.id}
                            className={`w-full py-3 rounded-xl text-sm font-bold transition-all flex items-center justify-center gap-2 ${
                                appliedIds.has(job.id)
                                ? 'bg-green-50 text-green-700 cursor-default'
                                : !showAllToggle 
                                    ? 'bg-gradient-to-r from-luGold-dark to-yellow-600 text-white shadow-lg hover:shadow-yellow-200 hover:-translate-y-0.5' 
                                    : 'bg-gray-900 text-white hover:bg-blue-600 shadow-lg'
                            }`}
                        >
                            {applyingId === job.id ? <Loader2 className="animate-spin" size={16}/> : 
                             appliedIds.has(job.id) ? <><CheckCircle size={16}/> Applied</> : 
                             'Apply Now'}
                        </button>
                    </div>
                ))}
            </div>
        )}
    </div>
  );
};

