import React, { useState, useEffect } from 'react';
import { JobPosting, JobApplication, Student } from '../types';
import { getOpenJobs, applyForJob, getUserApplications } from '../services/jobService';
import { Search, MapPin, Briefcase, DollarSign, Clock, Send, MessageSquare, CheckCircle, Loader2, Filter, AlertCircle } from 'lucide-react';
import JobChatModal from './JobChatModal';

interface JobPostingsPageProps {
  user: Student;
}

const JobPostingsPage: React.FC<JobPostingsPageProps> = ({ user }) => {
  const [activeTab, setActiveTab] = useState<'browse' | 'applications'>('browse');
  const [jobs, setJobs] = useState<JobPosting[]>([]);
  const [applications, setApplications] = useState<JobApplication[]>([]);
  const [loading, setLoading] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  // Application State
  const [applyingId, setApplyingId] = useState<string | null>(null);

  // Chat State
  const [selectedChatApp, setSelectedChatApp] = useState<JobApplication | null>(null);

  // Helper to determine user type safely
  const getUserType = () => {
      if (user.table_source) return user.table_source === 'students' ? 'student' : 'alumni';
      // Fallback logic if table_source is missing (e.g. legacy local storage)
      // Graduating students are definitely 'student'. 
      // If manually registered as Old Alumni, they might not have table_source in old cache, 
      // but usually the "New Alumni" flow is the default for recent users.
      return user.enrollment_status === 'Graduating' ? 'student' : 'student'; 
  };

  useEffect(() => {
    if (activeTab === 'browse') {
        fetchJobs();
    } else {
        fetchApplications();
    }
  }, [activeTab]);

  const fetchJobs = async () => {
      setLoading(true);
      try {
          const allJobs = await getOpenJobs();
          // We also need to know which ones we've already applied to, to update UI
          const userType = getUserType();
          const userApps = await getUserApplications(user.id!, userType);
          const appliedJobIds = new Set(userApps.map(app => app.job_posting_id));

          // Add a flag to jobs locally (not in type, but useful for UI)
          const jobsWithStatus = allJobs.map(job => ({
              ...job,
              hasApplied: appliedJobIds.has(job.id)
          }));

          // @ts-ignore
          setJobs(jobsWithStatus);
      } catch (e) {
          console.error(e);
      } finally {
          setLoading(false);
      }
  };

  const fetchApplications = async () => {
      setLoading(true);
      try {
          const userType = getUserType();
          const apps = await getUserApplications(user.id!, userType);
          setApplications(apps);
      } catch (e) {
          console.error(e);
      } finally {
          setLoading(false);
      }
  };

  const handleApply = async (jobId: string) => {
      // Removed window.confirm to prevent UI blocking issues
      setApplyingId(jobId);
      try {
          const userType = getUserType();
          if (!user.id) throw new Error("User ID not found.");

          await applyForJob(jobId, user.id, userType);

          // Refresh list to show "Applied"
          await fetchJobs();
          // Optional: Toast notification here
      } catch (e: any) {
          console.error("Apply Error:", e);
          alert(`Failed to apply: ${e.message || "Unknown error"}`);
      } finally {
          setApplyingId(null);
      }
  };

  const filteredJobs = jobs.filter(job => 
      job.job_title.toLowerCase().includes(searchTerm.toLowerCase()) || 
      job.company_name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      job.location.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="space-y-6 animate-fade-in pb-10">

        {/* Navigation Tabs */}
        <div className="flex gap-4 border-b border-gray-200 pb-1">
            <button 
                onClick={() => setActiveTab('browse')}
                className={`px-4 py-2 font-bold text-sm transition-colors border-b-2 ${activeTab === 'browse' ? 'border-blue-600 text-blue-600' : 'border-transparent text-gray-500 hover:text-gray-800'}`}
            >
                Browse Jobs
            </button>
            <button 
                onClick={() => setActiveTab('applications')}
                className={`px-4 py-2 font-bold text-sm transition-colors border-b-2 ${activeTab === 'applications' ? 'border-blue-600 text-blue-600' : 'border-transparent text-gray-500 hover:text-gray-800'}`}
            >
                My Applications
            </button>
        </div>

        {/* BROWSE TAB */}
        {activeTab === 'browse' && (
            <div className="space-y-6">
                {/* Search Bar */}
                <div className="relative">
                    <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={20} />
                    <input 
                        type="text" 
                        placeholder="Search by job title, company, or location..." 
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        className="w-full pl-12 pr-4 py-4 bg-white rounded-2xl border border-gray-100 shadow-sm focus:ring-2 focus:ring-blue-100 focus:border-blue-300 outline-none transition-all font-medium text-gray-700"
                    />
                </div>

                {loading ? (
                    <div className="flex justify-center py-20"><Loader2 className="animate-spin text-gray-300 w-8 h-8"/></div>
                ) : filteredJobs.length === 0 ? (
                    <div className="text-center py-20 bg-white rounded-3xl border border-dashed border-gray-200">
                        <Briefcase className="w-12 h-12 text-gray-300 mx-auto mb-4" />
                        <p className="text-gray-500 font-bold">No active job postings found.</p>
                    </div>
                ) : (
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        {filteredJobs.map((job: any) => (
                            <div key={job.id} className="bg-white p-6 rounded-3xl border border-gray-100 shadow-sm hover:shadow-lg transition-all duration-300 group flex flex-col h-full relative overflow-hidden">
                                {job.hasApplied && (
                                    <div className="absolute top-0 right-0 bg-green-100 text-green-700 text-[10px] font-bold px-3 py-1.5 rounded-bl-xl border-l border-b border-green-200">
                                        APPLIED
                                    </div>
                                )}

                                <div className="flex justify-between items-start mb-4">
                                    <div className="flex items-center gap-4">
                                        <div className="w-12 h-12 bg-gradient-to-br from-blue-500 to-blue-600 rounded-xl flex items-center justify-center text-white shadow-md">
                                            <Briefcase size={20} />
                                        </div>
                                        <div>
                                            <h3 className="font-bold text-gray-800 text-lg leading-tight group-hover:text-blue-600 transition-colors">{job.job_title}</h3>
                                            <p className="text-sm font-semibold text-gray-500">{job.company_name}</p>
                                        </div>
                                    </div>
                                </div>

                                <div className="space-y-3 mb-6 flex-grow">
                                    <div className="flex flex-wrap gap-2 text-xs font-bold text-gray-600">
                                        <span className="px-2.5 py-1 bg-gray-50 rounded-md border border-gray-200 flex items-center gap-1"><MapPin size={12}/> {job.location}</span>
                                        <span className="px-2.5 py-1 bg-gray-50 rounded-md border border-gray-200 flex items-center gap-1"><Clock size={12}/> {job.employment_type}</span>
                                        <span className="px-2.5 py-1 bg-gray-50 rounded-md border border-gray-200 flex items-center gap-1"><DollarSign size={12}/> {job.salary_range}</span>
                                    </div>
                                    <p className="text-sm text-gray-600 line-clamp-3 leading-relaxed">
                                        {job.job_description}
                                    </p>
                                </div>

                                <button 
                                    onClick={() => handleApply(job.id)}
                                    disabled={job.hasApplied || applyingId === job.id}
                                    className={`w-full py-3.5 rounded-xl font-bold text-sm flex items-center justify-center gap-2 transition-all ${
                                        job.hasApplied 
                                        ? 'bg-green-50 text-green-600 cursor-default'
                                        : 'bg-gray-900 text-white hover:bg-blue-600 shadow-lg hover:shadow-blue-200 hover:-translate-y-0.5'
                                    }`}
                                >
                                    {applyingId === job.id ? <Loader2 className="animate-spin" size={16}/> : 
                                     job.hasApplied ? <><CheckCircle size={16}/> Application Sent</> : 
                                     'Apply Now'}
                                </button>
                            </div>
                        ))}
                    </div>
                )}
            </div>
        )}

        {/* MY APPLICATIONS TAB */}
        {activeTab === 'applications' && (
            <div className="space-y-6">
                {loading ? (
                    <div className="flex justify-center py-20"><Loader2 className="animate-spin text-gray-300 w-8 h-8"/></div>
                ) : applications.length === 0 ? (
                    <div className="text-center py-20 bg-white rounded-3xl border border-dashed border-gray-200">
                        <Send className="w-12 h-12 text-gray-300 mx-auto mb-4" />
                        <p className="text-gray-500 font-bold">You haven't applied to any jobs yet.</p>
                        <button onClick={() => setActiveTab('browse')} className="mt-4 text-blue-600 font-bold hover:underline">Browse Active Jobs</button>
                    </div>
                ) : (
                    <div className="grid grid-cols-1 gap-4">
                        {applications.map((app) => (
                            <div key={app.id} className="bg-white p-5 rounded-2xl border border-gray-100 shadow-sm flex flex-col md:flex-row justify-between items-start md:items-center gap-4 hover:shadow-md transition-all">
                                <div className="flex items-center gap-4">
                                    <div className="w-12 h-12 bg-blue-50 text-blue-600 rounded-xl flex items-center justify-center">
                                        <Briefcase size={22} />
                                    </div>
                                    <div>
                                        <h4 className="font-bold text-gray-800 text-lg">{app.job?.job_title}</h4>
                                        <p className="text-sm text-gray-500 font-medium">{app.job?.company_name}</p>
                                        <p className="text-xs text-gray-400 mt-1">Applied on {new Date(app.applied_at).toLocaleDateString()}</p>
                                    </div>
                                </div>

                                <div className="flex items-center gap-3 w-full md:w-auto">
                                    <span className={`px-4 py-2 rounded-xl text-xs font-bold uppercase tracking-wide border ${
                                        app.application_status === 'Hired' ? 'bg-green-100 text-green-700 border-green-200' :
                                        app.application_status === 'Rejected' ? 'bg-red-100 text-red-700 border-red-200' :
                                        'bg-amber-50 text-amber-700 border-amber-100'
                                    }`}>
                                        {app.application_status}
                                    </span>

                                    <button 
                                        onClick={() => setSelectedChatApp(app)}
                                        className="flex-1 md:flex-initial flex items-center justify-center gap-2 px-5 py-2.5 bg-blue-600 text-white rounded-xl text-xs font-bold hover:bg-blue-700 transition-colors shadow-sm"
                                    >
                                        <MessageSquare size={16} /> Chat HR
                                    </button>
                                </div>
                            </div>
                        ))}
                    </div>
                )}
            </div>
        )}

        {/* Chat Modal */}
        {selectedChatApp && (
            <JobChatModal 
                application={selectedChatApp} 
                user={user} 
                onClose={() => setSelectedChatApp(null)} 
            />
        )}

    </div>
  );
};

export default JobPostingsPage;

import React, { useState, useEffect } from 'react';
import { JobPosting, Student } from '../types';
import { getOpenJobs, applyForJob, getUserApplications } from '../services/jobService';
import { Sparkles, Briefcase, MapPin, Loader2, CheckCircle, ToggleRight, ToggleLeft } from 'lucide-react';

interface ForYouPageProps {
  user: Student;
}

const ForYouPage: React.FC<ForYouPageProps> = ({ user }) => {
  const [loading, setLoading] = useState(true);
  const [matchedJobs, setMatchedJobs] = useState<JobPosting[]>([]);
  const [showAllToggle, setShowAllToggle] = useState(false);
  const [allJobsCache, setAllJobsCache] = useState<JobPosting[]>([]); // Cache for toggling
  const [applyingId, setApplyingId] = useState<string | null>(null);
  const [appliedIds, setAppliedIds] = useState<Set<string>>(new Set());

  // Helper to determine user type safely
  const getUserType = () => {
      if (user.table_source) return user.table_source === 'students' ? 'student' : 'alumni';
      return 'student'; // Fallback
  };

  useEffect(() => {
    fetchAndMatchJobs();
  }, []);

  const fetchAndMatchJobs = async () => {
    setLoading(true);
    try {
        const userType = getUserType();
        const [jobs, userApps] = await Promise.all([
            getOpenJobs(),
            getUserApplications(user.id!, userType)
        ]);

        const appSet = new Set(userApps.map(a => a.job_posting_id));
        setAppliedIds(appSet);
        setAllJobsCache(jobs);

        // --- MATCHING LOGIC ---
        const matches = jobs.filter(job => {
            let score = 0;
            const program = user.program.toLowerCase();
            const jobTitle = job.job_title.toLowerCase();
            const jobDesc = job.job_description.toLowerCase();
            const industry = job.industry.toLowerCase();

            // 1. Program Keyword Match (High Weight)
            const progKeywords = program.replace('bachelor of science in', '').replace('bachelor of', '').split(' ');
            const hasProgMatch = progKeywords.some(k => k.length > 3 && (jobTitle.includes(k) || jobDesc.includes(k)));

            if (hasProgMatch) score += 30;

            // 2. Exact Program Match (Very High Weight)
            if (program.includes('information technology') || program.includes('computer science')) {
                if (jobTitle.includes('developer') || jobTitle.includes('engineer') || jobTitle.includes('it') || industry.includes('tech')) score += 20;
            }
            if (program.includes('accountancy') || program.includes('accounting')) {
                if (jobTitle.includes('accountant') || jobTitle.includes('audit') || jobTitle.includes('finance')) score += 20;
            }
            if (program.includes('education')) {
                if (jobTitle.includes('teacher') || jobTitle.includes('tutor') || industry.includes('education')) score += 20;
            }

            // 3. Job Level (Fresh Grad Priority)
            if (user.year_level && parseInt(user.year_level) >= new Date().getFullYear()) {
                if (job.job_level.toLowerCase().includes('entry') || job.job_level.toLowerCase().includes('fresh') || job.job_level.toLowerCase().includes('associate')) {
                    score += 15;
                }
            }

            return score >= 15; // Threshold for "For You"
        });

        setMatchedJobs(matches);

    } catch (e) {
        console.error(e);
    } finally {
        setLoading(false);
    }
  };

  const handleApply = async (jobId: string) => {
      // Removed window.confirm
      setApplyingId(jobId);
      try {
          const userType = getUserType();
          if (!user.id) throw new Error("User ID not found");

          await applyForJob(jobId, user.id, userType);
          setAppliedIds(prev => new Set(prev).add(jobId));
      } catch (e: any) {
          console.error("Apply Error:", e);
          alert(`Error applying: ${e.message || "Unknown Error"}`);
      } finally {
          setApplyingId(null);
      }
  };

  const displayedJobs = showAllToggle ? allJobsCache : matchedJobs;

  return (
    <div className="space-y-6 animate-fade-in pb-10">

        {/* Header Area */}
        <div className="flex flex-col md:flex-row justify-between items-end gap-4 border-b border-gray-200 pb-4">
            <div>
                <div className="flex items-center gap-2 mb-1">
                    <Sparkles className="text-luGold-dark" size={20} />
                    <h2 className="text-xl font-bold text-gray-800">Jobs For You</h2>
                </div>
                <p className="text-sm text-gray-500">Curated based on your program <span className="font-bold text-gray-700">({user.program})</span> and profile.</p>
            </div>

            {/* Toggle */}
            <button 
                onClick={() => setShowAllToggle(!showAllToggle)}
                className="flex items-center gap-2 text-sm font-bold text-gray-600 hover:text-gray-900 transition-colors"
            >
                {showAllToggle ? <ToggleRight className="text-blue-600" size={32} /> : <ToggleLeft className="text-gray-400" size={32} />}
                Show All Jobs
            </button>
        </div>

        {loading ? (
            <div className="flex justify-center py-20"><Loader2 className="animate-spin text-gray-300 w-8 h-8"/></div>
        ) : displayedJobs.length === 0 ? (
            <div className="text-center py-20 bg-white rounded-3xl border border-dashed border-gray-200">
                <Sparkles className="w-12 h-12 text-gray-300 mx-auto mb-4" />
                <p className="text-gray-500 font-bold">No recommendations found yet.</p>
                <button onClick={() => setShowAllToggle(true)} className="mt-2 text-blue-600 text-sm font-bold hover:underline">View all jobs instead</button>
            </div>
        ) : (
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                {displayedJobs.map(job => (
                    <div key={job.id} className={`bg-white p-6 rounded-3xl border transition-all duration-300 relative group flex flex-col ${!showAllToggle ? 'border-luGold/30 shadow-lg shadow-yellow-500/5' : 'border-gray-100 shadow-sm hover:shadow-md'}`}>

                        {!showAllToggle && (
                            <div className="absolute top-4 right-4 text-[10px] font-bold uppercase tracking-wider text-luGold-dark bg-yellow-50 px-2 py-1 rounded-lg border border-yellow-100">
                                Recommended
                            </div>
                        )}

                        <div className="mb-4">
                            <h3 className="text-lg font-bold text-gray-900 group-hover:text-blue-600 transition-colors">{job.job_title}</h3>
                            <p className="text-sm font-semibold text-gray-500">{job.company_name}</p>
                        </div>

                        <div className="flex flex-wrap gap-2 mb-4 text-xs font-bold text-gray-600">
                            <span className="bg-gray-50 px-2 py-1 rounded border border-gray-100 flex items-center gap-1"><MapPin size={10}/> {job.location}</span>
                            <span className="bg-gray-50 px-2 py-1 rounded border border-gray-100">{job.employment_type}</span>
                            <span className="bg-gray-50 px-2 py-1 rounded border border-gray-100">{job.salary_range}</span>
                        </div>

                        <p className="text-sm text-gray-600 line-clamp-2 mb-6 flex-grow">{job.job_description}</p>

                        <button 
                            onClick={() => handleApply(job.id)}
                            disabled={appliedIds.has(job.id) || applyingId === job.id}
                            className={`w-full py-3 rounded-xl text-sm font-bold transition-all flex items-center justify-center gap-2 ${
                                appliedIds.has(job.id)
                                ? 'bg-green-50 text-green-700 cursor-default'
                                : !showAllToggle 
                                    ? 'bg-gradient-to-r from-luGold-dark to-yellow-600 text-white shadow-lg hover:shadow-yellow-200 hover:-translate-y-0.5' 
                                    : 'bg-gray-900 text-white hover:bg-blue-600 shadow-lg'
                            }`}
                        >
                            {applyingId === job.id ? <Loader2 className="animate-spin" size={16}/> : 
                             appliedIds.has(job.id) ? <><CheckCircle size={16}/> Applied</> : 
                             'Apply Now'}
                        </button>
                    </div>
                ))}
            </div>
        )}
    </div>
  );
};

export default ForYouPage;

import React, { useState, useEffect, useRef } from 'react';
import { JobApplication, JobMessage, Student } from '../types';
import { getMessages, sendMessage } from '../services/jobService';
import { Send, X, MessageSquare, Briefcase, User } from 'lucide-react';

interface JobChatModalProps {
  application: JobApplication;
  user: Student; // Current logged in user
  onClose: () => void;
}

const JobChatModal: React.FC<JobChatModalProps> = ({ application, user, onClose }) => {
  const [messages, setMessages] = useState<JobMessage[]>([]);
  const [newMessage, setNewMessage] = useState('');
  const [sending, setSending] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    fetchMessages();
    const interval = setInterval(fetchMessages, 3000); // Poll every 3s
    return () => clearInterval(interval);
  }, [application.id]);

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const fetchMessages = async () => {
    try {
        const data = await getMessages(application.id);
        setMessages(data);
    } catch (e) { console.error(e); }
  };

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  const handleSend = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!newMessage.trim()) return;

      setSending(true);
      try {
          const userTable = user.table_source || (user.enrollment_status === 'Graduating' ? 'students' : 'students'); // Default safe
          const userType = userTable === 'students' ? 'STUDENT' : 'ALUMNI';

          const payload: Partial<JobMessage> = {
              application_id: application.id,
              sender_type: userType,
              message: newMessage,
              is_read: false
          };

          if (userType === 'STUDENT') payload.student_id = user.id;
          else payload.alumni_id = user.id;

          await sendMessage(payload);
          setNewMessage('');
          fetchMessages();
      } catch (e) {
          alert("Failed to send message");
      } finally {
          setSending(false);
      }
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
        <div className="absolute inset-0 bg-gray-900/50 backdrop-blur-sm" onClick={onClose}></div>
        <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md h-[600px] flex flex-col relative z-10 overflow-hidden animate-in zoom-in-95 duration-200">

            {/* Header */}
            <div className="p-4 border-b border-gray-100 bg-gradient-to-r from-blue-600 to-blue-700 text-white flex justify-between items-center">
                <div className="flex items-center gap-3">
                    <div className="p-2 bg-white/20 rounded-lg backdrop-blur-sm">
                        <Briefcase size={20} />
                    </div>
                    <div>
                        <h3 className="font-bold text-sm leading-tight">{application.job?.company_name}</h3>
                        <p className="text-xs opacity-80">{application.job?.job_title}</p>
                    </div>
                </div>
                <button onClick={onClose} className="p-2 hover:bg-white/20 rounded-full transition-colors"><X size={20}/></button>
            </div>

            {/* Chat Body */}
            <div className="flex-grow p-4 overflow-y-auto bg-gray-50 space-y-3">
                {messages.length === 0 ? (
                    <div className="flex flex-col items-center justify-center h-full text-gray-400">
                        <MessageSquare size={48} className="mb-2 opacity-20"/>
                        <p className="text-sm font-medium">Start a conversation with HR</p>
                    </div>
                ) : (
                    messages.map((msg) => {
                        const isMe = msg.sender_type !== 'HR';
                        return (
                            <div key={msg.id} className={`flex ${isMe ? 'justify-end' : 'justify-start'}`}>
                                <div className={`flex items-end gap-2 max-w-[80%] ${isMe ? 'flex-row-reverse' : 'flex-row'}`}>
                                    <div className={`w-6 h-6 rounded-full flex items-center justify-center text-[10px] font-bold shrink-0 ${isMe ? 'bg-blue-200 text-blue-700' : 'bg-gray-200 text-gray-600'}`}>
                                        {isMe ? 'ME' : 'HR'}
                                    </div>
                                    <div className={`px-4 py-2 rounded-2xl text-sm shadow-sm ${
                                        isMe 
                                        ? 'bg-blue-600 text-white rounded-br-none' 
                                        : 'bg-white text-gray-800 border border-gray-100 rounded-bl-none'
                                    }`}>
                                        {msg.message}
                                    </div>
                                </div>
                            </div>
                        );
                    })
                )}
                <div ref={messagesEndRef} />
            </div>

            {/* Input */}
            <form onSubmit={handleSend} className="p-3 bg-white border-t border-gray-100 flex gap-2">
                <input 
                    type="text" 
                    value={newMessage}
                    onChange={(e) => setNewMessage(e.target.value)}
                    placeholder="Type your message..."
                    className="flex-grow bg-gray-100 rounded-full px-4 py-2.5 text-sm outline-none focus:ring-2 focus:ring-blue-100 transition-all"
                />
                <button 
                    type="submit" 
                    disabled={!newMessage.trim() || sending}
                    className="bg-blue-600 hover:bg-blue-700 text-white p-2.5 rounded-full transition-all disabled:opacity-50 disabled:scale-95 shadow-md"
                >
                    <Send size={18} />
                </button>
            </form>
        </div>
    </div>
  );
};

export default JobChatModal;
